package com.vidaysalud.veterinaria.pagoservicio.controller;import com.vidaysalud.veterinaria.pagoservicio.dto.*;import com.vidaysalud.veterinaria.pagoservicio.service.PagoService;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import java.time.LocalDateTime;import java.util.*;@RestController @RequestMapping("/api/v1/pagos") @RequiredArgsConstructor public class PagoController{private final PagoService s;@GetMapping public ResponseEntity<ApiResponse<List<PagoResponseDTO>>>l(){return ok("Pagos obtenidos",s.listar());}@GetMapping("/{id}")public ResponseEntity<ApiResponse<PagoResponseDTO>>b(@PathVariable Integer id){return ok("Pago encontrado",s.buscar(id));}@PostMapping public ResponseEntity<ApiResponse<PagoResponseDTO>>c(@Valid @RequestBody PagoRequestDTO d){return ResponseEntity.status(201).body(resp(HttpStatus.CREATED,"Pago creado",s.crear(d)));}@PutMapping("/{id}")public ResponseEntity<ApiResponse<PagoResponseDTO>>u(@PathVariable Integer id,@Valid @RequestBody PagoRequestDTO d){return ok("Pago actualizado",s.actualizar(id,d));}@PatchMapping("/{id}/estado")public ResponseEntity<ApiResponse<PagoResponseDTO>>e(@PathVariable Integer id,@Valid @RequestBody EstadoPagoRequestDTO d){return ok("Estado de pago actualizado",s.estado(id,d.getEstado()));}@DeleteMapping("/{id}")public ResponseEntity<ApiResponse<Void>>d(@PathVariable Integer id){s.eliminar(id);return ok("Pago eliminado",null);}private<T>ResponseEntity<ApiResponse<T>>ok(String m,T d){return ResponseEntity.ok(resp(HttpStatus.OK,m,d));}private<T>ApiResponse<T>resp(HttpStatus h,String m,T d){return ApiResponse.<T>builder().timestamp(LocalDateTime.now()).status(h.value()).mensaje(m).data(d).build();}}